// src/App.jsx — fully responsive, large book, with Index panel

import { useState, useRef, useEffect, useCallback } from "react";
import HTMLFlipBook from "react-pageflip";

import { DEFAULT_PAGES } from "./data/pages.js";
import BookPage from "./components/BookPage.jsx";
import BookIndex from "./components/BookIndex.jsx";
import ReferencePanel from "./components/ReferencePanel.jsx";
import NavBtn from "./components/NavBtn.jsx";
import KeyboardNav from "./components/KeyboardNav.jsx";
import LoginScreen from "./components/LoginScreen.jsx";
import AdminPanel from "./components/AdminPanel.jsx";

function useBookDimensions() {
  const [dim, setDim] = useState({ w: 420, h: 520, portrait: false });

  useEffect(() => {
    const calc = () => {
      const vw = window.innerWidth;
      const vh = window.innerHeight;
      // Use portrait mode for screens smaller than 768px (tablet breakpoint)
      const portrait = vw < 768;

      if (portrait) {
        // Single page mode - each page takes full width
        const w = Math.floor(Math.min(vw * 0.85, 400));
        const h = Math.floor(w * 1.35);
        setDim({ w, h, portrait: true });
      } else {
        // Two-page spread mode
        const maxSpreadW = vw * 0.85;
        const maxH = vh * 0.7;
        let w = Math.floor(maxSpreadW / 2);
        let h = Math.floor(w * 1.3);
        if (h > maxH) {
          h = Math.floor(maxH);
          w = Math.floor(h / 1.3);
        }
        w = Math.max(w, 240);
        h = Math.max(h, 310);
        setDim({ w, h, portrait: false });
      }
    };
    calc();
    window.addEventListener("resize", calc);
    return () => window.removeEventListener("resize", calc);
  }, []);

  return dim;
}

// Cover component for front and back
function BookCover({ type, pageW, pageH }) {
  const isFront = type === "front";

  return (
    <div
      style={{
        width: pageW,
        height: pageH,
        background: "linear-gradient(145deg, #1a1a2e 0%, #16213e 50%, #0f3460 100%)",
        borderRadius: "8px",
        display: "flex",
        flexDirection: "column",
        alignItems: "center",
        justifyContent: "center",
        position: "relative",
        overflow: "hidden",
        boxShadow: "inset 0 0 40px rgba(0,0,0,0.4), 4px 0 12px rgba(0,0,0,0.3)",
        border: "1px solid rgba(255,215,0,0.3)",
      }}
    >
      {/* Decorative border */}
      <div
        style={{
          position: "absolute",
          inset: 10,
          border: "2px solid rgba(255,215,0,0.4)",
          borderRadius: "4px",
          pointerEvents: "none",
        }}
      />

      {/* Sparkle decorations */}
      {[...Array(8)].map((_, i) => (
        <div
          key={i}
          style={{
            position: "absolute",
            top: `${10 + Math.random() * 80}%`,
            left: `${10 + Math.random() * 80}%`,
            fontSize: `${16 + Math.random() * 16}px`,
            opacity: 0.3 + Math.random() * 0.5,
            animation: `twinkle ${2 + Math.random() * 3}s ease-in-out infinite`,
            animationDelay: `${Math.random() * 2}s`,
            pointerEvents: "none",
          }}
        >
          {["✨", "⭐", "🌟", "💫"][Math.floor(Math.random() * 4)]}
        </div>
      ))}

      {/* Book image on cover */}
      <div
        style={{
          width: Math.min(pageW * 0.5, 120),
          height: Math.min(pageW * 0.5, 120),
          background: "url('https://cdn.pixabay.com/photo/2015/12/09/17/11/magic-book-1085246_640.jpg') center/cover",
          borderRadius: "50%",
          boxShadow: "0 8px 24px rgba(0,0,0,0.4), 0 0 0 3px rgba(255,215,0,0.3)",
          marginBottom: 20,
        }}
      />

      <h1
        style={{
          fontFamily: "'Bubblegum Sans', cursive",
          fontSize: `${Math.min(pageW * 0.08, 32)}px`,
          color: "#FFD700",
          textShadow: "0 2px 8px rgba(0,0,0,0.5)",
          margin: "8px 0 4px",
          textAlign: "center",
          padding: "0 15px",
        }}
      >
        {isFront ? "Magic Story Book" : "The End"}
      </h1>

      <p
        style={{
          fontFamily: "'Nunito', sans-serif",
          fontSize: `${Math.min(pageW * 0.035, 13)}px`,
          color: "rgba(255,255,255,0.7)",
          textAlign: "center",
          margin: 0,
          padding: "0 20px",
        }}
      >
        {isFront 
          ? "Open the book to begin your magical journey..." 
          : "Thank you for reading! May magic stay with you always."}
      </p>

      {isFront && (
        <div
          style={{
            position: "absolute",
            bottom: 20,
            fontSize: `${Math.min(pageW * 0.06, 22)}px`,
            color: "rgba(255,215,0,0.4)",
            fontFamily: "'Bubblegum Sans', cursive",
          }}
        >
          ✨📖✨
        </div>
      )}
    </div>
  );
}

export default function App() {
  const [pages, setPages] = useState(DEFAULT_PAGES);
  const [currentPage, setCurrentPage] = useState(0);
  const [showRef, setShowRef] = useState(false);
  const [showIndex, setShowIndex] = useState(false);
  const [showLogin, setShowLogin] = useState(false);
  const [showAdmin, setShowAdmin] = useState(false);
  const [isLoggedIn, setIsLoggedIn] = useState(false);
  const flipRef = useRef(null);
  const { w: pageW, h: pageH, portrait } = useBookDimensions();

  // Create book pages with front cover at start and end cover at the end
  const bookPages = [
    { id: "front-cover", isCover: true, isFront: true },
    ...pages,
    { id: "end-cover", isCover: true, isFront: false }
  ];

  const totalPages = bookPages.length;
  const progress = totalPages > 1 ? currentPage / (totalPages - 1) : 0;
  const activeItem = bookPages[currentPage];

  const onPage = useCallback((e) => {
    setCurrentPage(e.data);
    setShowRef(false);
  }, []);

  const prevPage = () => {
    if (flipRef.current && currentPage > 0) {
      flipRef.current.pageFlip().flipPrev();
    }
  };

  const nextPage = () => {
    if (flipRef.current && currentPage < totalPages - 1) {
      flipRef.current.pageFlip().flipNext();
    }
  };

  const goToPage = (pageIndex) => {
    if (flipRef.current && pageIndex >= 0 && pageIndex < totalPages) {
      flipRef.current.pageFlip().flip(pageIndex);
      setCurrentPage(pageIndex);
    }
  };

  // Get display text for current position
  const getPageDisplayText = () => {
    if (currentPage === 0) return "Cover";
    if (currentPage === totalPages - 1) return "End Cover";
    return `Page ${currentPage} of ${totalPages - 2}`;
  };

  // Adjust spread width calculation
  const spreadWidth = portrait ? pageW : Math.min(pageW * 2 + 8, window.innerWidth * 0.9);

  return (
    <div
      style={{
        minHeight: "100vh",
        background: "linear-gradient(145deg, #0a0a1a 0%, #1a0a3c 40%, #0c1a3c 70%, #060414 100%)",
        display: "flex",
        flexDirection: "column",
        alignItems: "center",
        justifyContent: "center",
        padding: "16px 12px",
        fontFamily: "'Nunito', sans-serif",
        position: "relative",
        boxSizing: "border-box",
      }}
    >
      <style>{`
        @import url('https://fonts.googleapis.com/css2?family=Bubblegum+Sans&family=Nunito:wght@400;600;700;800;900&display=swap');
        *, *::before, *::after { box-sizing: border-box; }

        @keyframes float {
          0%, 100% { transform: translateY(0) rotate(0deg); }
          50% { transform: translateY(-8px) rotate(2deg); }
        }

        @keyframes twinkle {
          0%, 100% { opacity: 0.3; transform: scale(1); }
          50% { opacity: 0.8; transform: scale(1.2); }
        }

        @keyframes pulse-btn {
          0%, 100% { box-shadow: 0 0 0 0 rgba(124, 58, 237, 0.5); }
          50% { box-shadow: 0 0 0 12px rgba(124, 58, 237, 0); }
        }

        @keyframes glow-bar {
          0%, 100% { opacity: 0.7; }
          50% { opacity: 1; }
        }

        .flip-book {
          margin: 0 auto;
        }

        .flip-book .page {
          border-radius: 4px;
        }
      `}</style>

      {/* Background decorations */}
      <div style={{ position: "fixed", inset: 0, pointerEvents: "none", overflow: "hidden" }}>
        <div style={{
          position: "absolute",
          top: "-20%",
          left: "-10%",
          width: "50vw",
          height: "50vw",
          borderRadius: "50%",
          background: "radial-gradient(circle, rgba(124, 58, 237, 0.15) 0%, transparent 70%)",
        }} />
        <div style={{
          position: "absolute",
          bottom: "-15%",
          right: "-10%",
          width: "45vw",
          height: "45vw",
          borderRadius: "50%",
          background: "radial-gradient(circle, rgba(6, 182, 212, 0.1) 0%, transparent 70%)",
        }} />
      </div>

      {/* Floating stars */}
      {["⭐", "🌟", "✨", "💫", "🌙", "⭐", "✨"].map((star, i) => (
        <div
          key={i}
          style={{
            position: "fixed",
            top: `${8 + i * 12}%`,
            left: i % 2 === 0 ? `${3 + i * 4}%` : `${85 - i * 2}%`,
            fontSize: `clamp(12px, ${1 + i * 0.2}vw, 20px)`,
            animation: `twinkle ${2 + i * 0.4}s ease-in-out infinite`,
            animationDelay: `${i * 0.3}s`,
            pointerEvents: "none",
            opacity: 0.4,
          }}
        >
          {star}
        </div>
      ))}

      {/* Title */}
      <div
        style={{
          color: "#fff",
          fontFamily: "'Bubblegum Sans', cursive",
          fontSize: "clamp(20px, 5vw, 36px)",
          marginBottom: "12px",
          textShadow: "0 2px 20px rgba(124, 58, 237, 0.6)",
          textAlign: "center",
          animation: "float 4s ease-in-out infinite",
        }}
      >
        📖 Magic Story Book
      </div>

      {/* Progress Bar */}
      <div
        style={{
          width: Math.min(spreadWidth, window.innerWidth * 0.9),
          height: 6,
          background: "rgba(255,255,255,0.1)",
          borderRadius: 3,
          marginBottom: "16px",
          overflow: "hidden",
        }}
      >
        <div
          style={{
            width: `${progress * 100}%`,
            height: "100%",
            background: "linear-gradient(90deg, #7c3aed, #06b6d4, #7c3aed)",
            backgroundSize: "200% 100%",
            borderRadius: 3,
            transition: "width 0.4s ease",
            animation: "glow-bar 2s ease-in-out infinite",
          }}
        />
      </div>

      {/* The Book */}
      <div
        style={{
          filter: "drop-shadow(0 20px 40px rgba(0,0,0,0.5))",
          position: "relative",
        }}
      >
        <HTMLFlipBook
          ref={flipRef}
          width={pageW}
          height={pageH}
          size="fixed"
          minWidth={280}
          maxWidth={600}
          minHeight={360}
          maxHeight={800}
          drawShadow={true}
          flippingTime={600}
          usePortrait={portrait}
          startZIndex={10}
          autoSize={false}
          mobileScrollSupport={false}
          showCover={true}
          onFlip={onPage}
          className="flip-book"
          style={{ margin: "0 auto" }}
        >
          {bookPages.map((item, idx) => (
            <div
              key={item.id || idx}
              style={{
                width: pageW,
                height: pageH,
                background: item.isCover ? "transparent" : "#fff",
                borderRadius: "4px",
              }}
            >
              {item.isCover ? (
                <BookCover
                  type={item.isFront ? "front" : "end"}
                  pageW={pageW}
                  pageH={pageH}
                />
              ) : (
                <BookPage
                  page={item}
                  pageNum={idx}
                  total={totalPages}
                  pageW={pageW}
                  pageH={pageH}
                  onShowRef={item.reference ? () => setShowRef(true) : null}
                />
              )}
            </div>
          ))}
        </HTMLFlipBook>
      </div>

      {/* Page indicator */}
      <div
        style={{
          color: "rgba(255,255,255,0.5)",
          fontSize: "clamp(11px, 2vw, 13px)",
          marginTop: "12px",
          fontWeight: 600,
        }}
      >
        {getPageDisplayText()}
      </div>

      {/* Navigation buttons */}
      <div
        style={{
          display: "flex",
          gap: "clamp(12px, 3vw, 20px)",
          marginTop: "16px",
          alignItems: "center",
          flexWrap: "wrap",
          justifyContent: "center",
        }}
      >
        <NavBtn onClick={prevPage} label="◀ Prev" disabled={currentPage === 0} />

        <button
          onClick={() => setShowIndex(true)}
          style={{
            width: "clamp(44px, 7vw, 52px)",
            height: "clamp(44px, 7vw, 52px)",
            borderRadius: "50%",
            background: "linear-gradient(135deg, #7c3aed, #06b6d4)",
            border: "none",
            display: "flex",
            alignItems: "center",
            justifyContent: "center",
            fontSize: "clamp(20px, 3.5vw, 24px)",
            cursor: "pointer",
            boxShadow: "0 4px 16px rgba(124, 58, 237, 0.4)",
            transition: "transform 0.15s, box-shadow 0.15s",
          }}
          onMouseEnter={(e) => e.currentTarget.style.transform = "scale(1.05)"}
          onMouseLeave={(e) => e.currentTarget.style.transform = "scale(1)"}
          title="Table of Contents"
        >
          📚
        </button>

        <NavBtn onClick={nextPage} label="Next ▶" disabled={currentPage >= totalPages - 1} />
      </div>

      {/* Admin button */}
      <button
        onClick={() => isLoggedIn ? setShowAdmin(true) : setShowLogin(true)}
        style={{
          position: "fixed",
          bottom: "16px",
          right: "16px",
          background: "linear-gradient(135deg, #7c3aed, #2563eb)",
          border: "none",
          color: "#fff",
          borderRadius: "12px",
          padding: "8px 16px",
          cursor: "pointer",
          fontWeight: 700,
          fontSize: "clamp(11px, 1.8vw, 13px)",
          fontFamily: "'Nunito', sans-serif",
          boxShadow: "0 4px 16px rgba(124, 58, 237, 0.4)",
          animation: "pulse-btn 2.5s infinite",
          display: "flex",
          alignItems: "center",
          gap: 6,
          zIndex: 500,
        }}
      >
        🔑 {isLoggedIn ? "Admin Panel" : "Admin"}
      </button>

      <KeyboardNav onPrev={prevPage} onNext={nextPage} />

      {/* Modals */}
      {showIndex && (
        <BookIndex
          pages={pages}
          currentPage={currentPage - 1}
          onGoTo={(pageIdx) => goToPage(pageIdx + 1)}
          onClose={() => setShowIndex(false)}
        />
      )}

      {showRef && activeItem && !activeItem.isCover && activeItem.reference && (
        <ReferencePanel
          reference={activeItem.reference}
          onClose={() => setShowRef(false)}
        />
      )}

      {showLogin && (
        <LoginScreen
          onLogin={() => {
            setIsLoggedIn(true);
            setShowLogin(false);
            setShowAdmin(true);
          }}
          onClose={() => setShowLogin(false)}
        />
      )}

      {showAdmin && (
        <AdminPanel
          pages={pages}
          setPages={setPages}
          onClose={() => setShowAdmin(false)}
        />
      )}
    </div>
  );
}
